local function send_json_response(status, data)
    ngx.status = status
    ngx.header["Content-Type"] = "application/json; charset=utf-8"
    ngx.say(cjson.encode(data))
    return ngx.exit(status)
end

local function connect_redis()
    local red, err = redis:new()
    if not red then
        return nil, "Failed to create Redis instance: " .. (err or "unknown")
    end

    red:set_timeout(REDIS_TIMEOUT)

    local ok, err = red:connect(REDIS_HOST, REDIS_PORT)
    if not ok then
        return nil, "Failed to connect to Redis at " .. REDIS_HOST .. ":" .. REDIS_PORT .. " - " .. (err or "unknown")
    end

    if REDIS_PASSWORD and REDIS_PASSWORD ~= "" then
        local res, err = red:auth(REDIS_PASSWORD)
        if not res then
            return nil, "Redis authentication failed: " .. (err or "unknown")
        end
    end

    return red, nil
end

local function release_redis(red)
    if not red then
        return
    end
    local ok, err = red:set_keepalive(REDIS_KEEPALIVE_TIMEOUT, REDIS_KEEPALIVE_POOL_SIZE)
    if not ok then
        ngx.log(ngx.WARN, "Failed to set Redis keepalive: ", err)
    end
end

local function parse_request_body()
    ngx.req.read_body()
    local body = ngx.req.get_body_data()
    if not body then
        return nil, "Empty request body"
    end

    local ok, data = pcall(cjson.decode, body)
    if not ok then
        return nil, "Invalid JSON in request body"
    end

    return data, nil
end

local function validate_command(cmd)
    if not cmd or type(cmd) ~= "string" or cmd == "" then
        return false, "Command must be a non-empty string"
    end

    local lower_cmd = string.lower(cmd)

    if BLOCKED_COMMANDS[lower_cmd] then
        return false, "Command '" .. cmd .. "' is blocked for security reasons"
    end

    if not ALLOWED_COMMANDS[lower_cmd] then
        return false, "Command '" .. cmd .. "' is not in the allowed commands list"
    end

    return true, nil
end

local function format_redis_result(result)
    if type(result) == "table" then
        local formatted = {}
        for i, v in ipairs(result) do
            if v == ngx.null then
                formatted[i] = cjson.null
            else
                formatted[i] = v
            end
        end
        return formatted
    elseif result == ngx.null then
        return cjson.null
    else
        return result
    end
end

local function execute_single_command(red, command, args)
    local ok, err = validate_command(command)
    if not ok then
        return nil, err
    end

    local lower_cmd = string.lower(command)

    -- Handle eval specially
    if lower_cmd == "eval" then
        if not args or #args < 2 then
            return nil, "EVAL requires at least a script and numkeys argument"
        end

        local script = args[1]
        local numkeys = tonumber(args[2])
        if not numkeys then
            return nil, "EVAL numkeys must be a number"
        end

        local eval_args = {}
        for i = 3, #args do
            eval_args[#eval_args + 1] = args[i]
        end

        local result, err = red:eval(script, numkeys, unpack(eval_args))
        if not result then
            return nil, "EVAL failed: " .. (err or "unknown")
        end
        return format_redis_result(result), nil
    end

    -- Handle evalsha
    if lower_cmd == "evalsha" then
        if not args or #args < 2 then
            return nil, "EVALSHA requires at least a sha1 and numkeys argument"
        end

        local sha1 = args[1]
        local numkeys = tonumber(args[2])
        if not numkeys then
            return nil, "EVALSHA numkeys must be a number"
        end

        local evalsha_args = {}
        for i = 3, #args do
            evalsha_args[#evalsha_args + 1] = args[i]
        end

        local result, err = red:evalsha(sha1, numkeys, unpack(evalsha_args))
        if not result then
            return nil, "EVALSHA failed: " .. (err or "unknown")
        end
        return format_redis_result(result), nil
    end

    -- Execute standard commands dynamically
    local func = red[lower_cmd]
    if not func then
        return nil, "Redis command method '" .. lower_cmd .. "' not found"
    end

    local result, err
    if args and #args > 0 then
        result, err = func(red, unpack(args))
    else
        result, err = func(red)
    end

    if not result then
        return nil, "Command '" .. command .. "' failed: " .. (err or "unknown")
    end

    return format_redis_result(result), nil
end

local function execute_pipeline(red, commands)
    if not commands or #commands == 0 then
        return nil, "Pipeline requires at least one command"
    end

    -- Validate all commands first
    for i, cmd_entry in ipairs(commands) do
        local command = cmd_entry.command or cmd_entry.cmd
        local ok, err = validate_command(command)
        if not ok then
            return nil, "Pipeline command #" .. i .. ": " .. err
        end
    end

    red:init_pipeline()

    for _, cmd_entry in ipairs(commands) do
        local command = string.lower(cmd_entry.command or cmd_entry.cmd)
        local args = cmd_entry.args or {}

        local func = red[command]
        if not func then
            red:cancel_pipeline()
            return nil, "Redis command method '" .. command .. "' not found"
        end

        if #args > 0 then
            func(red, unpack(args))
        else
            func(red)
        end
    end

    local results, err = red:commit_pipeline()
    if not results then
        return nil, "Pipeline execution failed: " .. (err or "unknown")
    end

    local formatted_results = {}
    for i, result in ipairs(results) do
        formatted_results[i] = format_redis_result(result)
    end

    return formatted_results, nil
end

-- Parse command from query string (GET request support)
local function parse_query_command()
    local args = ngx.req.get_uri_args()
    local command = args.cmd or args.command
    if not command then
        return nil, nil, "Missing 'cmd' or 'command' query parameter"
    end

    local cmd_args = {}
    -- Support args as comma-separated or indexed: arg1, arg2, ...
    if args.args then
        -- Comma-separated args
        for arg in string.gmatch(args.args, "[^,]+") do
            cmd_args[#cmd_args + 1] = arg
        end
    else
        -- Indexed args: arg1=foo&arg2=bar
        local i = 1
        while true do
            local val = args["arg" .. i]
            if not val then
                break
            end
            cmd_args[#cmd_args + 1] = val
            i = i + 1
        end
    end

    return command, cmd_args, nil
end

-- Rate limiting using shared dict (optional)
local function check_rate_limit()
    local limit_dict = ngx.shared.redis_api_limit
    if not limit_dict then
        return true -- No rate limiting configured
    end

    local client_ip = ngx.var.remote_addr
    local key = "rate:" .. client_ip
    local count, err = limit_dict:incr(key, 1, 0, 60) -- 60 second window

    if not count then
        ngx.log(ngx.ERR, "Rate limit incr failed: ", err)
        return true -- Allow on error
    end

    local max_requests = 1000 -- Max requests per minute per IP
    if count > max_requests then
        return false
    end

    return true
end

-- Main request handler
local function handle_request()
    -- Check rate limiting
    if not check_rate_limit() then
        return send_json_response(429, {
            success = false,
            error = "Rate limit exceeded. Please try again later."
        })
    end

    local method = ngx.req.get_method()
    local red, err = connect_redis()
    if not red then
        return send_json_response(503, {
            success = false,
            error = err
        })
    end

    -- GET request: single command via query parameters
    if method == "GET" then
        local command, args, parse_err = parse_query_command()
        if parse_err then
            release_redis(red)
            return send_json_response(400, {
                success = false,
                error = parse_err
            })
        end

        local result, exec_err = execute_single_command(red, command, args)
        release_redis(red)

        if exec_err then
            return send_json_response(400, {
                success = false,
                error = exec_err
            })
        end

        return send_json_response(200, {
            success = true,
            command = command,
            result = result
        })

    -- POST request: single command or pipeline via JSON body
    elseif method == "POST" then
        local data, parse_err = parse_request_body()
        if parse_err then
            release_redis(red)
            return send_json_response(400, {
                success = false,
                error = parse_err
            })
        end

        -- Check if this is a pipeline request
        if data.pipeline then
            local results, exec_err = execute_pipeline(red, data.pipeline)
            release_redis(red)

            if exec_err then
                return send_json_response(400, {
                    success = false,
                    error = exec_err
                })
            end

            return send_json_response(200, {
                success = true,
                pipeline = true,
                results = results
            })
        end

        -- Single command execution
        local command = data.command or data.cmd
        if not command then
            release_redis(red)
            return send_json_response(400, {
                success = false,
                error = "Missing 'command' or 'cmd' field in request body"
            })
        end

        local args = data.args or {}
        if type(args) ~= "table" then
            release_redis(red)
            return send_json_response(400, {
                success = false,
                error = "'args' must be an array"
            })
        end

        local result, exec_err = execute_single_command(red, command, args)
        release_redis(red)

        if exec_err then
            return send_json_response(400, {
                success = false,
                error = exec_err
            })
        end

        return send_json_response(200, {
            success = true,
            command = command,
            result = result
        })

    -- Unsupported method
    else
        release_redis(red)
        return send_json_response(405, {
            success = false,
            error = "Method " .. method .. " not allowed. Use GET or POST."
        })